    html.push_str("<section class=\"panel\"><h2>Trace Stream Runner</h2><pre id=\"trace-stream-runner-detail\" class=\"detail\"></pre></section>");
    html.push_str("<section class=\"panel\"><h2>Runtime</h2>");
