        let address = session
            .launched
            .as_ref()
            .and_then(|launched| launched.async_runtime.as_ref())
            .and_then(|runtime| runtime.transport.as_ref())
            .and_then(|transport| transport.address.clone())
            .expect("in-process runtime address");

